    end
  end
end

assert(#missing == 0, "missing L0 bank stencils: " .. table.concat(missing, ", "))
assert(#bad == 0, "bad L0 bank stencils: " .. table.concat(bad, "; "))

print("ok - SpongeJIT generated bank has native L0 floor coverage for opcodes 0..84")

