static void check(int cond, const char *msg) {
  if (!cond) {
    fprintf(stderr, "FAIL: %s\n", msg);
    exit(1);
  }
}

int main(void) {
  SponL1Op ops[5];
  SponL1Image img;
  SponTValueABI stack[8];
  SponTValueABI k[8];
  SponExecCtx ctx;

  memset(ops, 0, sizeof(ops));
  for (int i = 0; i < 5; i++) {
    ops[i].opcode = SPON_OP_ADDI;
    ops[i].a = 0;
    ops[i].b = 0;
    ops[i].c = i + 1;
  }

  spon_l1_image_init(&img);
  check(spon_l1_project(ops, 0, 5, SPON_FACT_I64_SLOT(0), SPON_FACT_I64_SLOT(0), &img) == 0,
        "project ADDI span from generated L1 bank");
  check(img.code != NULL && img.code_size > 0, "projected image has native bytes");
  check(img.n_choices > 0, "projected image has selected stencils");

  memset(stack, 0, sizeof(stack));
  memset(k, 0, sizeof(k));
  memset(&ctx, 0, sizeof(ctx));
  ctx.stack = stack;
  ctx.k = k;
  stack[0].value_ = 0;
  stack[0].tt_ = SPON_LUA_VNUMINT;
  ctx.exit_kind = 99;

  check(spon_l1_run(&img, &ctx) == SPON_EXIT_NONE, "projected image exits ok");
  check(stack[0].value_ == 15, "projected image computes ADDI chain");
  check(stack[0].tt_ == SPON_LUA_VNUMINT, "projected image preserves integer tag");

  memset(&ctx, 0, sizeof(ctx));
  ctx.stack = stack;
  ctx.k = k;
  stack[0].value_ = 0;
  stack[0].tt_ = SPON_LUA_VNIL;
  ctx.exit_kind = 99;

  check(spon_l1_run(&img, &ctx) == SPON_EXIT_GUARD, "projected image guard exits on non-i64");
  check(stack[0].value_ == 0, "guard exit does not execute ADDI chain");

